<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
    body { 
        background-color: #121212; 
        color: #e0e0e0; 
        font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; 
        display: flex; 
        flex-direction: column; 
        align-items: center; 
        justify-content: center; 
        height: 100vh; 
        margin: 0; 
    }
    #bars { 
        display: flex; 
        align-items: flex-end; 
        justify-content: center; 
        gap: 4px; 
        width: 95%; 
        max-width: 800px; 
        height: 300px; 
        background: #1e1e1e; 
        padding: 15px; 
        border-radius: 8px; 
        margin-bottom: 20px; 
        box-shadow: 0 4px 6px rgba(0,0,0,0.3);
    }
    .bar { 
        background-color: #4a90e2; 
        width: 15px; 
        margin: 0 2px;
        transition: height 0.1s ease, background-color 0.1s ease; 
        min-height: 5px; 
        border-radius: 2px 2px 0 0; 
    }
    .active { background-color: #ff6b6b !important; }
    .sorted { background-color: #51cf66 !important; }

    .controls { display: flex; gap: 15px; }
    button { 
        padding: 10px 20px; 
        font-size: 16px; 
        cursor: pointer; 
        background: #333; 
        color: white; 
        border: none; 
        border-radius: 4px; 
        transition: background 0.2s, opacity 0.2s; 
    }
    button:hover:not(:disabled) { background: #555; }
    button:disabled { opacity: 0.5; cursor: not-allowed; }
</style>
</head>
<body>

<div id="bars"></div>
<div class="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
</div>

<script>
    // State variables for Bubble Sort
    let data = [];
    let i = 0; 
    let j = 0;
    let isSorting = false;

    const barsContainer = document.getElementById('bars');

    function initArray() {
        data = Array.from({length: 20}, () => Math.floor(Math.random() * 100) + 1);
        resetSortState();
        render();
    }

    function resetSortState() {
        i = 0;
        j = 0;
    }

    // API Implementation
    window.viz = {
        array: () => [...data],

        setArray: (a) => {
            data = a.slice(); 
            resetSortState();
            render();
        },

        sorted: () => {
            for (let k = 0; k < data.length - 1; k++) {
                if (data[k] > data[k+1]) return false;
            }
            return true;
        },

        sortStep: () => {
            const n = data.length;

            // Base case: empty or single element is sorted
            if (n <= 1) {
                resetSortState();
                render();
                return true;
            }

            // Check if outer loop finished
            if (i >= n - 1) {
                resetSortState();
                render();
                return true;
            }

            // Perform one comparison/swap step
            const idx1 = j;
            const idx2 = j + 1;

            // Highlight active bars for visualization
            highlightBars([idx1, idx2]);

            if (data[idx1] > data[idx2]) {
                [data[idx1], data[idx2]] = [data[idx2], data[idx1]];
            }

            // Advance inner index
            j++;

            // Check if inner loop needs reset and outer increment
            if (j >= n - 1 - i) {
                j = 0;
                i++;
            }

            render();

            // Check if sorting is complete after this step
            if (i >= n - 1) {
                resetSortState();
                return true;
            }

            return false;
        }
    };

    function highlightBars(indices) {
        const barEls = document.querySelectorAll('.bar');
        // Clear active classes first
        barEls.forEach(el => el.classList.remove('active'));

        indices.forEach(idx => {
            if (idx < barEls.length && idx >= 0) {
                barEls[idx].classList.add('active');
            }
        });
    }

    function render() {
        barsContainer.innerHTML = '';
        const maxVal = Math.max(...data, 1); // Avoid div by zero

        data.forEach((val, idx) => {
            const bar = document.createElement('div');
            bar.className = 'bar';
            bar.style.height = `${(val / maxVal) * 100}%`;
            barsContainer.appendChild(bar);
        });

        // Re-apply active class after render because DOM was cleared
        if (i < data.length - 1 && j >= 0) {
             highlightBars([j, j+1]);
        } else if (data.length > 0) {
             Array.from(barsContainer.children).forEach(el => el.classList.add('sorted'));
        }
    }

    // Button Handlers
    document.getElementById('sort').addEventListener('click', async () => {
        if (isSorting) return;
        isSorting = true;
        const btn = document.getElementById('sort');
        btn.disabled = true;

        while (!window.viz.sorted()) {
            window.viz.sortStep();
            await new Promise(r => setTimeout(r, 50)); // Animation delay
        }

        isSorting = false;
        btn.disabled = false;
    });

    document.getElementById('shuffle').addEventListener('click', () => {
        if (isSorting) return;
        const arr = window.viz.array();
        for (let k = arr.length - 1; k > 0; k--) {
            const m = Math.floor(Math.random() * (k + 1));
            [arr[k], arr[m]] = [arr[m], arr[k]];
        }
        window.viz.setArray(arr);
    });

    document.getElementById('reset').addEventListener('click', () => {
        if (isSorting) return;
        initArray();
    });

    // Initial Load
    initArray();

</script>
</body>
</html>
